const fs = require('fs');
const path = require('path');

const textFileTypes = [
  'org', 'md', 'markdown', 'txt', 'html', 'xml',
  'appleplist', 'asm', 'asp', 'batch', 'c', 'cs', 'css', 'csv', 'eml', 'go', 'html', 'ini', 'internetshortcut', 'java', 'javascript', 'json', 'latex', 'lisp', 'makefile', 'markdown', 'mht', 'mum', 'pem', 'perl', 'php', 'powershell', 'python', 'rdf', 'rst', 'rtf', 'ruby', 'rust', 'scala', 'shell', 'smali', 'sql', 'svg', 'symlinktext', 'txt', 'vba', 'winregistry', 'xml', 'yaml'
];
const binaryFileTypes = ['pdf', 'jpg', 'jpeg', 'png', 'webp'];
const validFileTypes = textFileTypes.concat(binaryFileTypes);

function isSupportedFileType(filePath) {
  const fileExtension = filePath.split('.').pop().toLowerCase();
  return validFileTypes.includes(fileExtension);
}

function processDirectory(filesToPush, folderPath) {
  try {
    const files = fs.readdirSync(folderPath, { withFileTypes: true });
    for (const file of files) {
      if (file.name.startsWith('.')) continue;
      const filePath = path.join(folderPath, file.name);
      if (file.isFile() && isSupportedFileType(filePath)) {
        filesToPush.push(filePath);
      } else if (file.isDirectory()) {
        processDirectory(filesToPush, filePath);
      }
    }
  } catch (err) {
    console.error(`Error reading directory ${folderPath}:`, err.message);
  }
}

const files = $input.getNodeParameter('files') || [];
const folders = $input.getNodeParameter('folders') || [];
let filesToPush = [];

for (const file of files) {
  if (fs.existsSync(file.path)) {
    filesToPush.push(file.path);
  }
}

for (const folder of folders) {
  if (fs.existsSync(folder.path)) {
    processDirectory(filesToPush, folder.path);
  }
}

return { filesToPush };

const fs = require('fs');

function filenameToMimeType(filename) {
  const extension = filename.split('.').pop();
  const mimeMap = {
    'pdf': 'application/pdf',
    'png': 'image/png',
    'jpg': 'image/jpeg',
    'jpeg': 'image/jpeg',
    'webp': 'image/webp',
    'md': 'text/markdown',
    'markdown': 'text/markdown',
    'org': 'text/org'
  };
  return mimeMap[extension] || 'text/plain';
}

const filesToPush = $input.getNodeParameter('filesToPush') || [];
const lastSync = $input.getNodeParameter('lastSync') || [];
const binaryFileTypes = ['pdf', 'jpg', 'jpeg', 'png', 'webp'];

const filesDataToPush = [];

for (const filePath of filesToPush) {
  try {
    const stats = fs.statSync(filePath);
    const lastSyncEntry = lastSync.find(f => f.path === filePath);

    if (lastSyncEntry && stats.mtime.toISOString() < lastSyncEntry.datetime) {
      continue;
    }

    const encoding = binaryFileTypes.includes(filePath.split('.').pop()) ? 'binary' : 'utf8';
    const fileContent = fs.readFileSync(filePath, { encoding });
    const mimeType = filenameToMimeType(filePath);

    filesDataToPush.push({
      path: filePath,
      content: fileContent,
      mimeType: mimeType,
      encoding: encoding
    });
  } catch (err) {
    console.error(`Error processing file ${filePath}:`, err.message);
  }
}

return { filesDataToPush };

const now = new Date().toISOString();
const filesToPush = $input.getNodeParameter('filesToPush') || [];

const lastSync = filesToPush.map(filePath => ({
  path: filePath,
  datetime: now
}));

return { lastSync };
